var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"쿨럭! ","JPN":"ガハッ！","ENG":"*Cough!* ","TWN":"咳咳！"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하아……. 하아…….","JPN":"はあ……はあ……","ENG":"Haa… Haa…","TWN":"呼……呼……"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"안색이 좋지 않군요.","JPN":"顔色がよくありませんね。","ENG":"You look rather pale.","TWN":"你的臉色好像不太好，"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"역시 피를 너무 많이 뽑아낸 걸지도 모르겠어요.","JPN":"やはり血を抜きすぎたかもしれません。","ENG":"Perhaps we've drawn too much blood from you after all.","TWN":"是因為被抽太多血的關係嗎？"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"……말수가 줄어들었군요.","JPN":"……口数が減りましたね。","ENG":"…You've grown rather taciturn.","TWN":"……話也變少了呢。"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"억지로 수다스러운 척을 할 이유가 사라졌으니 당신에게도 좋은 일이겠죠.","JPN":"無理やり饒舌なふりをする理由も消えたので、あなたにとっても良いことでしょう。","ENG":"I suppose it's a good thing, as you won't have to pretend to be so chatty.","TWN":"現在不用再硬裝作很聒噪，對你來說也算是好事一件吧？"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"당신은…… 꽤 내성적인 분 같으니까요.","JPN":"あなたは……とても内気な性格のようですので。","ENG":"Because it seems… you're more of an introvert.","TWN":"你……應該算是內向的人吧？"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하, 제가 좀…… 그런 편이긴 하죠.","JPN":"ハハ、確かに……僕ってそんなキャラなんですよね。","ENG":"Haha… Yeah, I guess I can be like that…","TWN":"哈哈～對啊……我滿內向的。"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"또 농담으로 얼버무리려 드는군요.","JPN":"また冗談で誤魔化そうとしていますね。","ENG":"And there you go trying to let jest cover your true self.","TWN":"又用開玩笑的方式來呼攏過去。"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"괜찮습니다. 곧 자신에게 솔직해져야 할 때가 올 테니까요.","JPN":"いいでしょう。もうじき自分に正直にならなければならない時が来ますから。","ENG":"Don't worry. It shall soon be time for you to be honest with yourself.","TWN":"沒關係，你很快就笑不出來了。"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"기다리는 동안, 옛날 이야기를 하나 들려 드리죠.","JPN":"待つ間に、昔話を一つお聞かせしましょう。","ENG":"Let me tell you a tale while we wait.","TWN":"等待的同時我跟你說個故事吧！"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"아주 옛날에…… 구도자라고 불리던 남자가 있었습니다.","JPN":"昔々……求道者と呼ばれた男がいました。","ENG":"Long, long ago… There was a man who was called the Seeker of Truth.","TWN":"很久很久以前……有個叫作求道者的男人，"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"이런 이야기에 흔하디 흔한, 세상을 구할 사명을 지니고 태어난 자였죠.","JPN":"彼はこんな話ではありふれた、世界を救う使命を持って生まれた者でした。","ENG":"The Seeker was destined to save the world, much like other heroes of tales like this.","TWN":"在這種故事裡，一定都會有個背負拯救世界的使命而誕生的人，"},"stage":{"bg":"MAINSTREAM_7010011","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"하지만 흔히들 그렇듯이 결국 성공하진 못했습니다.","JPN":"しかし、これもまたありふれた話で、結局成し遂げることはできませんでした。","ENG":"And like those other heroes, the Seeker also failed in the end.","TWN":"不過通常都是失敗收場。"},"stage":{"bg":"MAINSTREAM_7010011","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"뭐, 현실에서도 무언가를 지키는 것 보다는 파괴하는 게 훨씬 더 쉬우니까…… ","JPN":"まあ、現実でも何かを守るより破壊するほうがずっと簡単ですから……","ENG":"Even in reality, destroying something is much easier than protecting it… ","TWN":"這也沒什麼，因為在現實世界裡也是一樣，破壞總比守護來得容易……"},"stage":{"bg":"MAINSTREAM_7010011","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그게 구도자의 잘못은 아니겠죠.","JPN":"それは求道者の過ちではないでしょう。","ENG":"But that was not the Seeker's fault.","TWN":"這完全不能怪求道者。"},"stage":{"bg":"MAINSTREAM_7010011","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"하지만 그 멍청한 남자는 포기하지 못했습니다.","JPN":"しかし、その愚かな男は諦められませんでした。","ENG":"Regardless, this foolish man could not give up.","TWN":"但問題是，那個愚蠢的男人不肯放棄。"},"stage":{"bg":"MAINSTREAM_7010011","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"얌전히 자신의 실패를 받아들이고 죽어 버리면 좋았을 텐데…….","JPN":"大人しく自分の失敗を受け入れて死んでしまえばよかったのに。","ENG":"It would have behooved him if he could simply accept his failure and perish…","TWN":"他應該乖乖地接受失敗就這樣死去……"},"stage":{"bg":"MAINSTREAM_7010011","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"기어이 복수를 하기로 마음먹었거든요.","JPN":"復讐することを決心したのです。","ENG":"But he took it upon himself to take vengeance.","TWN":"但他執意要報仇。"},"stage":{"bg":"MAINSTREAM_7010012","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하……. 괜히 성녀님이 아니신가 보네요.","JPN":"ハハ……聖女様と呼ばれているだけありますね。","ENG":"Haha… I guess they don't call you a Saintess for nothing.","TWN":"哈哈……這完全不像聖女的作風呢？"},"stage":{"bg":"MAINSTREAM_7010012","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"용서와 화해에 대해…… 설교라도 하고 싶으신 건가요……?","JPN":"許しと和解について……説教でもしたいんですか……？","ENG":"Did you want to give a sermon on forgiveness and reconciliation?","TWN":"你該不會是要跟我談什麼……饒恕還是和解的吧……？"},"stage":{"bg":"MAINSTREAM_7010012","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그럴 리가요.","JPN":"まさか。","ENG":"Of course not.","TWN":"當然不是！"},"stage":{"bg":"MAINSTREAM_7010012","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"전하의 말씀대로, 전 노예 출신입니다.","JPN":"殿下のおっしゃるとおり、私は奴隷出身です。","ENG":"As His Highness inferred, I was once a slave.","TWN":"如殿下所言，我只是個奴隸，"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"당신이 살고 있는 이 세계에서는 이미 오래 전에 사라져버린 것 같지만 노예라는 건 꽤 비참한 직업이죠.","JPN":"あなたが住んでいるこの世界ではとうの昔に\\n消えてしまったようですが、奴隷というものはとても凄惨な身分です。","ENG":"Although I understand slaves have long been emancipated in your world… it is a most tragic occupation.","TWN":"雖然在你的世界裡已經沒有奴隸制度，但其實奴隸是個非常卑賤的工作。"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"묻겠습니다, 이방인이여. 노예들이 누구를 가장 두려워하는지 아시나요?","JPN":"お尋ねしましょう、異邦人よ。奴隷が最も恐れる存在が誰なのか知っていますか？","ENG":"Let me ask you, outsider. Do you know whom slaves fear the most?","TWN":"外邦人我問你，你知道奴隸最怕什麼嗎？"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"글쎄요……. 주인인가요?","JPN":"さあ……主人でしょうか？","ENG":"I don't know… Their master?","TWN":"這個嘛……是主人嗎？"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"아뇨. 주인에게 노예는 재산입니다. 자기 물건을 함부로 다루는 사람은 그리 많지 않죠.","JPN":"いいえ。主人にとって奴隷は財産です。自分の所有物を粗雑に扱う者は多くありません。","ENG":"No. A slave is the master's property. Not many would abuse their own property.","TWN":"不，對主人來說奴隸是財產，很少人會不愛惜自己的東西。"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"노예가 가장 두려워하는 자들은, 바로 다른 노예들입니다.","JPN":"奴隷が最も恐れるものは、他の奴隷です。","ENG":"The people slaves fear the most are other slaves.","TWN":"奴隸最怕的就是其他的奴隸！"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"낡은 옷가지, 딱딱한 빵 조각, 마지막 남은 자존심.","JPN":"古びた服、硬いパンの一切れ、最後に残った自尊心。","ENG":"The same slaves with nothing but ragged clothes, rock-hard crumbs of bread, and what little pride they've left.","TWN":"破舊的衣服、乾掉的麵包、最後的自尊心，"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"가치는 없지만, 그저 지니고 있다는 것만으로도 누군가한테는 빼앗을 이유가 됩니다.","JPN":"価値は無くとも、ただ持っているというだけで誰かにとっては奪う理由になります。","ENG":"As worthless such things seem to some, these are valuable enough to take from others.","TWN":"雖然這些都不值錢，卻是奴隸僅有的，深怕會被誰搶走。"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그런 자들과 지내면 싫어도 깨닫게 되죠.","JPN":"そんな者たちと過ごすと嫌でも悟ります。","ENG":"When you spend enough time among them, you come to realize…","TWN":"和這樣的人相處，就算不願意你也會發現，"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"살아남기 위해서는 빼앗기지 않아야 하고, 빼앗기지 않으려면 싸울 수밖에 없다는 사실을.","JPN":"生き残るためには奪われてはならず、奪われないためには戦うしかないという事実を。","ENG":"That in order to survive, you mustn't let them take anything away from you. And to do that, you must fight.","TWN":"想要存活下去，就必須保護好自己的東西不被搶走，想要東西不被搶走就必須起來戰鬥！"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그리고 그 방식이 무자비하고 잔혹할수록 세상이 당신을 존중해 준다는 것을.","JPN":"そして、その方法が無慈悲で残酷なほど、世界はあなたを尊重してくれるということを。","ENG":"And the world only respects you when you're ready to be merciless and cruel in that fight.","TWN":"而且手段越殘忍越冷血，越能得到別人的尊重。"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그 싸움을 사람들은 복수라고 부릅니다.","JPN":"その戦いを人々は復讐と呼びます。","ENG":"Most people call that fight \\"revenge.\\"","TWN":"而人們將這樣的行為稱之為報仇。"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그런 제가 복수를 부정할 리 있겠습니까?","JPN":"そんな私が復讐を否定するはずがないでしょう？","ENG":"Now, then. Would I ever denounce anyone for taking such revenge?","TWN":"所以我怎麼可能否定報仇呢？"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그럼 어째서……?","JPN":"じゃあ、どうして……？","ENG":"Then why…?","TWN":"你到底想說什麼……？"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"하지만 그 실패자는 제대로 된 복수자도 되지 못했다는 게 문제였죠.","JPN":"しかし、その失敗者はまともな復讐者にもなれなかったということが問題だったのです。","ENG":"The problem with the Seeker was that he couldn't even complete his revenge properly.","TWN":"問題就是那個失敗者連復仇者也做不好。"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"말했듯이 복수란 살아남기 위한 방법입니다.","JPN":"お話ししたとおり、復讐とは生き残るための手段です。","ENG":"As I've mentioned, revenge is a means of survival.","TWN":"就如同我剛說的，報仇是活下去的手段，"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그러기 위해선 한가지 원칙을 지켜야 하죠.","JPN":"そのためには一つの原則を守らなければなりません。","ENG":"Thus one must abide by one immutable principle when taking revenge.","TWN":"但必須遵守一個原則。"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그게 뭐죠?","JPN":"それは何ですか？","ENG":"Which is what?","TWN":"報仇也講原則？"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"……복수의 대상은 반드시 타인이어야 합니다.","JPN":"……復讐の対象は必ず他人でなければなりません。","ENG":"…That revenge must be taken on someone else other than yourself.","TWN":"……就是報仇的對象必須是其他人。"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"복수의 이유는 위선이든, 죄책감이든, 분노든 상관없습니다.","JPN":"復讐の理由は偽善でも、罪悪感でも、怒りでも構いません。","ENG":"Now, it doesn't matter if your vengeance is driven by hypocrisy, guilt, or rage.","TWN":"不管報仇的理由是什麼，是偽善也好，是罪惡感也好，是憤怒也好，都無所謂。"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"복수할 대상이 있다는 것만으로도 살아갈 수 있기 때문이죠.","JPN":"復讐する対象がいるということだけで生きていけるからです。","ENG":"The very fact that you have someone to take revenge on will keep you alive.","TWN":"因為只要報仇的對象就能夠活下去。"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"하지만 구도자는 남을 탓하면서 비참하게 살아갈 용기도, 죽어서 자신의 사명을 포기할 만한 이기심도 없는 자였어요.","JPN":"しかし、求道者は他人のせいにしながら\\n惨めに生きていく勇気も、死んで自分の使命を諦めるほどの利己心もない者でした。","ENG":"But the Seeker was neither courageous enough to go on living while blaming others, nor selfish enough to forgo his calling and die.","TWN":"但求道者既沒勇氣卸責苟活，也沒膽量用結束自己生命的方式來放棄使命。"},"stage":{"bg":"MAINSTREAM_7010013","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그래서 그는 자기 자신을 복수의 대상으로 삼았습니다.","JPN":"そこで彼は自分自身を復讐の対象にしました。","ENG":"So he decided to take revenge upon himself.","TWN":"於是他將自己視為報仇的對象。"},"stage":{"bg":"MAINSTREAM_7010013","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그건 살아가는 자의 자세라고 볼 수 없죠.","JPN":"それは生きていく者の姿勢とは言えません。","ENG":"That is no way to live.","TWN":"但這不是一個要存活下去的人該有的行為。"},"stage":{"bg":"MAINSTREAM_7010013","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"삶도, 죽음도 선택하지 못한 구도자는 죽지도 살지도 못하는 존재가 되었고…….","JPN":"生も死も選択できなかった求道者は、死ぬことも生きることもできない存在となり……","ENG":"As such, the Seeker became neither living nor dead…","TWN":"無法在生與死中做出抉擇的求道者，於是便處在一個求生不能求死不得的狀態……"},"stage":{"bg":"MAINSTREAM_7010013","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"결국 먹혀 버렸습니다.","JPN":"結局食べられてしまいました。","ENG":"And ultimately, he was devoured.","TWN":"結局就是被吞噬掉。"},"stage":{"bg":"MAINSTREAM_7060010","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"옛날 이야기라더니…… 그리 재미있지는 않네요.","JPN":"昔話と聞いて楽しみにしていたのに……あまり面白くないですね。","ENG":"That's mighty boring for a fairy tale.","TWN":"這個故事……好像有點無聊。"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"저한테 그 이야기를 들려 준 이유가 뭐죠?","JPN":"僕にその話をした理由はなんですか？","ENG":"Is there a reason you told me this story?","TWN":"為什麼要跟我說這個故事？"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그 구도자의 직계 후손이, 바로 당신입니다.","JPN":"その求道者の直系の子孫があなただからです。","ENG":"Yes. Because you are a direct descendent of the Seeker.","TWN":"因為那個求道者的直系後裔就是你。"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"……뭐라고요?","JPN":"……は？","ENG":"…What?","TWN":"……你說什麼？"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"말 그대로입니다.","JPN":"言葉どおりの意味です。","ENG":"You heard me.","TWN":"就我剛說的。"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"자신의 번뇌를 이기지 못한 구도자는 결국 미쳐 버린 마룡이 되었습니다.","JPN":"自分の煩悩に打ち勝てなかった求道者は結局、狂ってしまった魔龍になりました。","ENG":"Having failed to overcome his Kleshas, the Seeker ended up becoming a mad Demon Dragon.","TWN":"無法勝過煩惱的求道者後來走火入魔變成魔龍，"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그리고는 스스로 몸을 찢어 몇몇 인간들에게 용의 피를 전승시켰죠.","JPN":"そして自ら体を裂き、いくらかの人間に龍の血を伝承させました。","ENG":"He then shredded his own body and passed on the Dragon Blood to several humans.","TWN":"還將自己的身體撕裂後，把龍血過給幾個人。"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그 중, 이번 세대에서 가장 진한 용혈을 이어받은 자가 바로 당신입니다.","JPN":"その中でも、今の世代で最も濃い龍血を受け継いだ者があなたです。","ENG":"Of those people, you were chosen to receive the thickest strain of Dragon Blood in this generation.","TWN":"而你就是身上流著純正龍血的人之一。"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"……그다지 기뻐할 만한 일은 아닌 것 같네요.","JPN":"……あまり喜ぶようなことではなさそうですね。","ENG":"…That doesn't sound like anything to be happy about.","TWN":"……怎麼聽起來似乎不是值得令人開心的事？"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"현명하군요.","JPN":"賢明ですね。","ENG":"You are wise.","TWN":"你說的沒錯。"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"대부분의 어리석은 자들은 용의 피를 이어받았다는 것을 행운으로 여깁니다.","JPN":"愚かな者の多くは龍の血を受け継いだことを幸運に思っています。","ENG":"Most fools consider themselves fortunate to be heirs of the Dragon Blood.","TWN":"大部分的人都以為身上流有龍血是件幸運的事，"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"하지만 용혈의 힘은 저주에 불과하죠.","JPN":"しかし龍血の力は呪いにすぎません。","ENG":"When in truth, the blood is nothing but a curse.","TWN":"但龍血的力量不過就是詛咒，"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"자신이 이루지 못한 소망과 번뇌를 후손에게 강제하기 위한 장치.","JPN":"自分が果たせなかった願いと煩悩を子孫に強制するための装置。","ENG":"It forces the Seeker's descendants to carry on his own hope and Kleshas.","TWN":"是求道者將自己無法完成的夢想和煩惱強加給後裔的工具，"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"구도자가 만들어낸 운명의 구속구입니다.","JPN":"求道者が作り出した運命の拘束具です。","ENG":"It is the fate binder crafted by the Seeker.","TWN":"是他創造的命運拘束器。"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하지만…… 전 여지껏 구속 받는다고 느낀 적이 없는데요?","JPN":"しかし……僕はこれまで拘束されていると感じたことありませんよ？","ENG":"But… I've never felt bound by any of this.","TWN":"可是……我從來沒有受到拘束的感覺？"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그럴 겁니다. 당신의 보호자가 지금까지 일처리를 꽤 잘했기 때문이죠.","JPN":"そうでしょうね。あなたの保護者が今まで真面目に保護してくれたおかげでしょう。","ENG":"Of course not. That's because your guardian has dealt with that most artfully thus far.","TWN":"我想也是，因為你的保護人把你保護得很好。"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"……그건 또 무슨 소리죠?","JPN":"……それはまた、どういうことですか？","ENG":"…And what's that supposed to mean?","TWN":"……這又是什麼意思？"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"본래라면 제가 말해 주지 않더라도 용혈의 계승자는 자신의 본질을 스스로 깨닫게 되어 있습니다.","JPN":"本来なら私が言わなくても龍血の継承者は自ら自分の本質を悟るものです。","ENG":"Normally, the heir of Dragon Blood is supposed to know their true nature, even without me telling them.","TWN":"原本就算我沒告訴你這些，龍血的繼承人也會自己覺醒過來，"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그 역시 당신의 몸에 흐르는 용혈의 저주 중 하나이니까요.","JPN":"それもまた、あなたの体に流れる龍血の呪いの一つですから。","ENG":"That is, after all, one of the curses of the Dragon Blood flowing within you.","TWN":"這也是你體內龍血的詛咒之一。"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"진실에 대해 알게 될수록 혈맥에 새겨진 광기가 강해지고…….","JPN":"真実について知れば知るほど血脈に刻まれた狂気が増し……","ENG":"And the more they learn about the truth, the madness ingrained in the blood grows stronger…","TWN":"知道越多真相，烙印在血脈中的狂氣就會越強烈……"},"stage":{"bg":"MAINSTREAM_7050010","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"결국 구도자가 남긴 저주에 몸을 완전히 빼앗기게 됩니다.","JPN":"最終的に、求道者が遺した呪いに体を完全に奪われることになります。","ENG":"In the end, they lose themselves entirely to the curse left by the Seeker.","TWN":"最後肉體就會完全被求道者留下的詛咒所佔據。"},"stage":{"bg":"MAINSTREAM_7050010","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그 후에는…… 그저 용이 되어야 한다는 강박만 남은 채, 인간도 용도 아닌 괴물로 전락해 버리죠.","JPN":"その後は……\\nただ龍にならなければという強迫観念だけが残され、\\n人間でも龍でもない化け物に堕ちてしまいます。","ENG":"After that… they turn into monsters that are neither Dragon nor human, driven by the obsession to become Dragons.","TWN":"然後……就會一心執著於要變成龍，但結局是墮落成人也不是龍也不是的怪物。"},"stage":{"bg":"MAINSTREAM_7050010","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"당신의 부모님이 그랬듯이.","JPN":"あなたの両親がそうだったように。","ENG":"Just like your parents.","TWN":"就像你的父母親一樣。"},"stage":{"bg":"MAINSTREAM_7050010","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"후손의 역량에 따라, 광기가 발현되는 시기는 각기 다릅니다.","JPN":"子孫の力量によって、狂気の発現時期はそれぞれ異なります。","ENG":"The madness sets in at different times, depending on the heir's capabilities.","TWN":"狂氣顯露出來的時間點會根據後裔的能力而有所不同。"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"당신의 보호자는 아마 당신에게 아무런 설명도 해주지 않았을 겁니다.","JPN":"おそらく、あなたの保護者はあなたに何の説明もしてくれなかったでしょう。","ENG":"Your guardian likely provided you no explanation.","TWN":"你的保護人應該沒跟你說過這些事吧？"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그리고 극단적으로 용혈의 사용을 억눌렀겠죠. ","JPN":"そして極端に龍血の使用を抑えたはずです。","ENG":"And it's likely she took excessive measures to inhibit your Dragon Blood. ","TWN":"甚至還會使用極端的手段阻止你使用龍血吧？"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"사용하면 죽여버린다든가, 뭐 그런 협박이 가장 간단하겠군요.","JPN":"使えば殺すなど、まあ似たような脅迫が最も簡単な方法でしょうね。","ENG":"Perhaps threatening to kill you if you used it would be the simplest way to do so.","TWN":"譬如說恐嚇你：敢用的話就殺掉你。這種恐嚇的效果好又不費力。"},"stage":{"bg":"MAINSTREAM_430010","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"MAINSTREAM_430010","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"거기에 더해서 가혹한 훈련이나, 실전을 통해 힘을 길러주었을 겁니다.","JPN":"それに加えて過酷な訓練や実戦によって力を養わせてくれたはずです。","ENG":"Your guardian also likely put you through brutal training and combat to make you stronger.","TWN":"再透過嚴格的訓練或是實戰培養你的能力，"},"stage":{"bg":"MAINSTREAM_7030011","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"당신이 용혈을 최대한 오래 억누를 수 있도록.","JPN":"あなたが龍血を出来るだけ長く抑えられるように。","ENG":"That would ensure that you could repress the Dragon Blood as long as possible.","TWN":"讓你盡可能地抑制住龍血。"},"stage":{"bg":"MAINSTREAM_7030011","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"표정을 보아하니 역시 내 추측이 맞았나 보군요.","JPN":"その顔を見ると、やはり私の推測は当たったようですね。","ENG":"The look on your face confirms the veracity of my conjectures.","TWN":"看你的表情，應該全被我說中了吧？"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"하지만 그런 <color=#ffd34c>관리</color>에도 결국은 한계가 있습니다.","JPN":"しかしそんな<color=#ffd34c>管理</color>にも限界はあります。","ENG":"But there's only so much such <color=#ffd34c>management</color> can do.","TWN":"但這樣的<color=#ffd34c>方法</color>終究只是一時的。"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"이제 저를 통해 진실의 실마리를 접했으니, 광기의 발현은 더욱 앞당겨지겠죠.","JPN":"私によって真実の糸口に接した以上、狂気の発現はさらに早まるでしょう。","ENG":"Now that I've unveiled the truth to you, your madness will set in much sooner.","TWN":"現在我把真相告訴你後，就會加速狂氣的顯露。"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"살짝 밀어버린 눈덩이가 점점 가속도를 더해가는 것처럼요.","JPN":"そっと押し転がした雪玉が、徐々に加速して大きくなっていくように。","ENG":"Just as the snowball accelerates when given a light push down the hill.","TWN":"就像雪球一樣，會越滾越大。"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그래서…… 절 괴롭히고 파멸시키기 위해 이런 이야기를 하신 건가요?","JPN":"それで……僕を苦しませて破滅させるためにこんな話をしたのですか？","ENG":"So… You told me all this to torture and destroy me?","TWN":"你告訴我這些……是想折磨我？還是毀掉我？"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"……처음에 말했을 텐데요.","JPN":"……最初に言ったはずです。","ENG":"…Did I not tell you?","TWN":"……我一開始不就說了嗎？"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"당신에게 구원의 기회를 주기 위해서라고요.","JPN":"あなたに救いの機会を与えるためと。","ENG":"This is to grant you salvation.","TWN":"我是要給你得救贖的機會。"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"구원……?","JPN":"救い……？","ENG":"Salvation?","TWN":"救贖……？"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"용혈의 계승자들이 광기에 삼켜지는 까닭은, 결국 진정한 용이 되지 못한 탓입니다.","JPN":"龍血の継承者たちが狂気に飲み込まれる理由は、真の龍になれなかったせいです。","ENG":"Heirs of the Dragon Blood succumb to their madness when they fail to become Dragons.","TWN":"龍血的繼承者之所以會被狂氣吞噬，說到底就是因為無法變成真正的龍。"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그리고 진정한 용이 되지 못하는 까닭은, 구도자가 남긴 번뇌를 이겨내지 못했기 때문이죠.","JPN":"そして真の龍になれない理由は、求道者が遺した煩悩に打ち勝てないからです。","ENG":"The reason they cannot become Dragons is because they fail to overcome the Kleshas left by the Seeker.","TWN":"而之所以無法成為真正的龍，就是因為無法勝過求道者留下的煩惱。"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그러니 번뇌의 근원을 제거할 수만 있다면…….","JPN":"なので煩悩の根源さえ排除できれば……","ENG":"Thus if you could remove the cause of the Kleshas…","TWN":"所以只要解決掉煩惱的根源……"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"진정한 용이 되어 파멸이 예정된 운명에서 벗어날 수 있습니다.","JPN":"真の龍となり、予定された破滅の運命から逃れることができます。","ENG":"You can become a true Dragon and escape your fate of doom.","TWN":"就可以成為真正的龍，擺脫原本注定會滅亡的命運。"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하…… 그러니까 돌아 돌아…… 결국 용인지 뭔지가 되라는 말이군요.","JPN":"ハハ……つまり回りに回って……結論は龍人になれってことですね。","ENG":"Haha… So in the end, you're just trying to convince me to become a Dragon.","TWN":"哈哈……說來說去……結果還是要我變成龍嘛。"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"좋아요. 살면서 비늘 하나 돋은 적 없는데 이렇게까지 들볶으시니 궁금해지긴 하네요.","JPN":"いいですよ。今まで鱗一枚すら生えたことはないですが、ここまで煽られたら気になりますね。","ENG":"Very well. I don't know why you're so insistent, seeing as I've never sprouted a single scale all my life. So now I'm a bit curious.","TWN":"好哇，雖然我活到現在還沒長過鱗片，但你一直這樣力勸我，搞得我也開始有點好奇呢！"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그 구도자라는 조상님부터 제 부모님에 이르기까지, 아무도 해내지 못한 일을 어떻게 하란 거죠?","JPN":"その求道者という先祖から僕の両親に至るまで\\n誰もやり遂げられなかったことを、どうして僕ができるんですか？","ENG":"What makes you think I can do this when not even my \\"ancestor\\" or my parents could?","TWN":"那求道者和我父母都辦不到的事，你要我怎麼辦呢？"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"간단합니다. 이야기에도 흔히 나오는 방법이죠.","JPN":"簡単です。これも物語に出てくるありふれた方法です。","ENG":"The answer is simple. It often appears in the tales as well.","TWN":"非常簡單，也是故事中常出現的方法，"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"제물을 바치는 겁니다.","JPN":"生贄を捧げるのです。","ENG":"You must offer a sacrifice.","TWN":"就是獻祭。"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"제물……?","JPN":"生贄……？","ENG":"A sacrifice?","TWN":"獻祭……？"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"네, 용을 완성하는 것은 언제나 순결한 처녀의 제물이죠.","JPN":"はい、龍を完成させるのはいつだって純潔な処女の生贄を捧げることです。","ENG":"Yes. As in the stories, a pure virgin is always sacrificed to complete the Dragon.","TWN":"對，通常要完成儀式就需要獻上純潔的處女對吧？"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그리고 지금 제물이 되기 위해 태어난 존재가 이곳으로 오고 있습니다.","JPN":"そして今、生贄になるために生まれた存在がこちらに向かっています。","ENG":"And the being who was created to become that sacrifice is on her way here right now.","TWN":"而那個注定要成為祭物的人正往這裡而來。"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"설마……. 미나 양 말인가요?","JPN":"まさか……ミナさんのことですか？","ENG":"You don't mean… Mina, do you?","TWN":"你說的該不會是……米娜？"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그렇습니다. 이방인이여.","JPN":"そのとおりです、異邦人よ。","ENG":"That is correct, outsider.","TWN":"答對囉。"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"오래 전, 구도자에게 넘을 수 없는 절망을 선사한 자.","JPN":"はるか昔、求道者に乗り越えられない絶望を与えた者。","ENG":"The one who granted the Seeker insurmountable despair long, long ago.","TWN":"很久以前，將無法跨越的絕望帶給求道者，"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"결국 그가 스스로의 번뇌에 빠져 미쳐 버리게 만든 자.","JPN":"彼が自らの煩悩にまみれ、狂う原因となった者。","ENG":"The one who made the Seeker drive himself to madness in his Kleshas.","TWN":"害他陷入自己的煩惱而走火入魔的人，"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"우린 그녀를 <color=#ffd34c>저주받은 늑대</color>라 부릅니다.","JPN":"我々は彼女を<color=#ffd34c>呪われた狼</color>と呼びます。","ENG":"We call her <color=#ffd34c>the Cursed Wolf</color>.","TWN":"我們稱她為<color=#ffd34c>受詛咒的狼</color>。"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"스승님도 그렇고…… 당신들도 대체 왜 그렇게 미나 양에게 집착하는 거죠?","JPN":"師匠もですが……あなたたちはなぜそこまでミナさんに執着するんですか？","ENG":"First the Master, and now you guys… Why's everyone so obsessed with Mina?","TWN":"師父這樣，你也這樣……你們到底為什麼要一直針對米娜？"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"대체 미나 양의 정체가 뭐길래…….","JPN":"いったいミナさんの正体は何者で……","ENG":"I mean, who is she, really?","TWN":"米娜的真實身分到底是誰……"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"지금 당신에게는 중요하지 않은 이야기입니다.","JPN":"今のあなたに重要ではありません。","ENG":"The answer to that is of little consequence to you right now.","TWN":"她到底是誰對你而言不重要，"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"중요한 건 그녀야말로 용혈에 묶인 저주의 근원이고…….","JPN":"重要なことは彼女こそ龍血に囚われた呪いの根源であり……","ENG":"What matters is that she is the source of the Dragon Blood's curse…","TWN":"重要的是，她就是龍血詛咒的根源……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그녀를 제물로 바쳐야만, 당신이 구원받을 수 있다는 사실입니다.","JPN":"彼女を生贄に捧げることこそが、あなたが救われる唯一の方法という事実です。","ENG":"And that you may find salvation only when you offer her up as a sacrifice.","TWN":"她一定要成為祭物獻祭，你才能得到救贖。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};